// modules/tasks/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'tasks',
  description: 'Handles task creation, assignment, and management utilities.',

  dependencies: { modules: ['auth'] },

  exposes: {
    routes: [
      { method: 'POST', path: '/tasks/create', auth: true },
      { method: 'GET',  path: '/tasks/:id',   auth: true },
      { method: 'PUT',  path: '/tasks/:id',   auth: true },
      { method: 'DELETE', path: '/tasks/:id', auth: true },
      { method: 'POST', path: '/tasks/:id/mark-as-read', auth: true },
    ],
    functions: ['createTask', 'getTask', 'updateTask', 'deleteTask', 'markTaskAsRead'],
    types: ['Task', 'TaskError'],
  },

  sideEffects: [
    'writes to: tasks table',
    'reads from: users table',
    'reads from: sessions table',
  ],

  invariants: [
    'A task must always be assigned to exactly one user',
    'Marking a task as read should not error on subsequent calls',
  ],
});

